(66, 'Earphone True Wireless G70', '2312021280054', 'standard', 'C128', 1, 3, 1, 1, 1, 58, 17, 0.00, 0, 0, 0, 0, 0, '', '0000-00-00', '0000-00-00', 0, 1, '202409080650101.jpg', '', 0, 0, 0, 0, 0, 0, '', '', '', '', '<h1 style=@text-align: right;@>هیدفۆنی وایەرلێس جی٧٠</h1>\n                    <p style=@text-align: right;@>&nbsp;</p>\n                    <h2 style=@text-align: right;@>تایبەتمەندیەکانی</h2>\n                    <p style=@text-align: right;@>هیدفۆنی بێ وایەر</p>\n                    <p style=@text-align: right;@>سیستەمی گونجاو :&nbsp;ئەندرۆید / ئی ئۆ ئێس / ویندۆس</p>\n                    <p style=@text-align: right;@>وەشانی بلوتوز :&nbsp;٥.٣</p>\n                    <p style=@text-align: right;@>توانای پاتری :&nbsp;٣٠ میلی ئەمپێر</p>\n                    <p style=@text-align: right;@>توانای پاتری سندوقی شەحنکردنەوە :&nbsp;٢٥٠ میلی ئەمپێر</p>\n                    <p style=@text-align: right;@>شێوازی شەحنکردنەوە :&nbsp;شەحنکردنەوەی جۆری سی</p>\n                    <p style=@text-align: right;@>تەمەنی پاتری : نزیکەی ٤ بۆ ٥ کاتژمێر</p>\n                    <p style=@text-align: right;@>&nbsp;</p>\n                    <h1>Earphone True Wireless G70</h1>\n                    <p style=@text-align: justify;@>&nbsp;</p>\n                    <h2>Specification</h2>\n                    <p>Product Type :&nbsp;Wireless Earbuds</p>\n                    <p>Brand :&nbsp;UiiSii</p>\n                    <p>Model :&nbsp;TWS-G70</p>\n                    <p>Compatible Systems :&nbsp;ios/android/Windows</p>\n                    <p>Bluetooth Version :&nbsp;5.3</p>\n                    <p>Battery Capacity :&nbsp;30 mAh</p>\n                    <p>Charging Box Battery Capacity :&nbsp;250 mAh</p>\n                    <p>Charging Method :&nbsp;TYPE-C charging</p>\n                    <p>Buds Battery Life :&nbsp;About 4 to 5 hours</p>\n                    <p>&nbsp;</p>', '', '', 1, 0, 0, '', '', '0000-00-00 00:00:00', '0000-00-00 00:00:00', '0', '', '0', 0),
